import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { User, Shield, Mail, Trash2, Edit, Save, X } from 'lucide-react';

const Perfil = () => {
  const [perfil, setPerfil] = useState(null);
  const [usuarios, setUsuarios] = useState([]); // Lista para o proprietário
  const [loading, setLoading] = useState(true);
  const [editandoNome, setEditandoNome] = useState(false);
  const [novoNome, setNovoNome] = useState('');

  useEffect(() => {
    carregarDados();
  }, []);

  const carregarDados = async () => {
    setLoading(true);
    const { data: { user } } = await supabase.auth.getUser();

    // 1. Puxar meu perfil
    const { data: meuPerfil } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', user.id)
      .single();

    setPerfil(meuPerfil);
    setNovoNome(meuPerfil.nome);

    // 2. Se eu for proprietário, puxar todos os usuários
    if (meuPerfil.tipo_usuario === 'proprietario') {
      const { data: todosUsuarios } = await supabase
        .from('profiles')
        .select('*')
        .order('nome', { ascending: true });
      setUsuarios(todosUsuarios);
    }
    setLoading(false);
  };

  const atualizarMeuNome = async () => {
    const { error } = await supabase
      .from('profiles')
      .update({ nome: novoNome })
      .eq('id', perfil.id);

    if (!error) {
      setPerfil({ ...perfil, nome: novoNome });
      setEditandoNome(false);
      alert("Nome atualizado!");
    }
  };

  const alterarTipoUsuario = async (id, novoTipo) => {
    if (perfil.tipo_usuario !== 'proprietario') return;
    
    const { error } = await supabase
      .from('profiles')
      .update({ tipo_usuario: novoTipo })
      .eq('id', id);

    if (!error) carregarDados();
  };

  const excluirUsuario = async (id) => {
    if (!window.confirm("Tem certeza? Isso não apagará o login, apenas o perfil.")) return;
    
    const { error } = await supabase
      .from('profiles')
      .delete()
      .eq('id', id);

    if (!error) carregarDados();
  };

  if (loading) return <div style={{ padding: '20px' }}>Carregando perfil...</div>;

  return (
    <div style={{ padding: '30px', maxWidth: '800px', margin: '0 auto' }}>
      <h2 style={{ display: 'flex', alignItems: 'center', gap: '10px', color: '#0f172a' }}>
        <User size={24} /> Meu Perfil
      </h2>

      {/* CARD DO MEU PERFIL */}
      <div style={cardStyle}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            {editandoNome ? (
              <div style={{ display: 'flex', gap: '10px' }}>
                <input 
                  value={novoNome} 
                  onChange={(e) => setNovoNome(e.target.value)}
                  style={inputStyle}
                />
                <button onClick={atualizarMeuNome} style={saveBtnStyle}><Save size={18}/></button>
                <button onClick={() => setEditandoNome(false)} style={cancelBtnStyle}><X size={18}/></button>
              </div>
            ) : (
              <h3 style={{ margin: 0 }}>{perfil.nome} <Edit size={16} onClick={() => setEditandoNome(true)} style={{cursor:'pointer', color:'#64748b'}}/></h3>
            )}
            <p style={{ color: '#64748b', fontSize: '0.9rem', margin: '5px 0' }}>
              <Shield size={14} /> {perfil.tipo_usuario.toUpperCase()}
            </p>
          </div>
        </div>
      </div>

      {/* ÁREA DO PROPRIETÁRIO */}
      {perfil.tipo_usuario === 'proprietario' && (
        <div style={{ marginTop: '40px' }}>
          <h3 style={{ color: '#0f172a' }}>Gestão de Usuários</h3>
          <div style={{ display: 'grid', gap: '15px' }}>
            {usuarios.map(u => (
              <div key={u.id} style={userItemStyle}>
                <span>{u.nome} ({u.tipo_usuario})</span>
                <div style={{ display: 'flex', gap: '10px' }}>
                  <select 
                    value={u.tipo_usuario} 
                    onChange={(e) => alterarTipoUsuario(u.id, e.target.value)}
                    style={selectStyle}
                  >
                    <option value="comum">Comum</option>
                    <option value="proprietario">Proprietário</option>
                  </select>
                  <button onClick={() => excluirUsuario(u.id)} style={deleteBtnStyle}>
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

// Estilos rápidos
const cardStyle = { backgroundColor: '#fff', padding: '20px', borderRadius: '16px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)', marginTop: '20px' };
const userItemStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '12px', backgroundColor: '#fff', borderRadius: '12px', border: '1px solid #e2e8f0' };
const inputStyle = { padding: '8px', borderRadius: '8px', border: '1px solid #cbd5e1' };
const saveBtnStyle = { background: '#22c55e', color: '#fff', border: 'none', borderRadius: '8px', padding: '8px', cursor: 'pointer' };
const cancelBtnStyle = { background: '#ef4444', color: '#fff', border: 'none', borderRadius: '8px', padding: '8px', cursor: 'pointer' };
const deleteBtnStyle = { background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer' };
const selectStyle = { padding: '5px', borderRadius: '6px', border: '1px solid #cbd5e1' };

export default Perfil;
